// INPUT: Set of m vectors in Rⁿ, each of dimension n
// OUTPUT: true if linearly independent, false otherwise

FUNCTION isLinearlyIndependent(vectors[]):
 m = vectors.length
 n = vectors[0].length

 // Form matrix with vectors as rows or columns
 matrix A = createMatrix(vectors)

 // Perform Gaussian elimination
 rref = rowReduceToRREF(A)

 // Count pivot positions (non-zero rows)
 pivots = countPivots(rref)

 // Independent if pivots = number of vectors
 IF pivots == m:
 RETURN true
 ELSE:
 RETURN false

// INPUT: Spanning set S of vectors in Rⁿ
// OUTPUT: A basis (maximally independent subset)

FUNCTION extractBasis(spanningSet[]):
 matrix A = createMatrix(spanningSet) // as rows

 // Row reduce to echelon form
 echelon = gaussianElimination(A)

 // Find pivot columns
 pivotCols = findPivotColumns(echelon)

 // Extract corresponding vectors from original set
 basis = []
 FOR i IN pivotCols:
 basis.append(spanningSet[i])

 RETURN basis

// Example usage:
// spanningSet = [(1,2,3), (2,4,6), (1,1,1)]
// basis = extractBasis(spanningSet) → [(1,2,3), (1,1,1)]

// INPUT: Matrix A (m×n)
// OUTPUT: Dimension of column space (rank)

FUNCTION columnSpaceDimension(A):
 // Method 1: Row reduce and count pivots
 rref = rowReduceToRREF(A)
 rank = countPivotColumns(rref)
 RETURN rank

// Alternative: Using orthogonal Triangularization
FUNCTION columnSpaceDimensionQR(A):
 Q, R = QRDecomposition(A) // Gram-Schmidt
 // R has same rank as A
 rank = countNonZeroDiagonal(R)
 RETURN rank

// Example:
// A = [[1,2,3],
// [2,4,6],
// [3,6,9]]
// columnSpaceDimension(A) → 1 (rank = 1)

