// INPUT: Matrix A (m×n)
// OUTPUT: Basis for null space and its dimension

FUNCTION nullSpaceBasis(A):
 // Row reduce to find RREF
 R = rowReduceToRREF(A)

 // Identify free variables (non-pivot columns)
 pivotCols = findPivotColumns(R)
 freeCols = []
 FOR j = 0 TO n-1:
 IF j NOT IN pivotCols:
 freeCols.append(j)

 // For each free variable, set it to 1 (others 0), solve for pivots
 basisVectors = []
 FOR each f IN freeCols:
 // Create vector with f-th component = 1, others free = 0
 x = zeros(n)
 x[f] = 1

 // Solve for pivot variables from RREF equations
 FOR each p IN pivotCols:
 x[p] = -R[equationOf(p)][f] // from R×x = 0

 basisVectors.append(x)

 RETURN basisVectors

